import{_ as a,o as s,c as t,a2 as i}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/installation.md","filePath":"en/guide/installation.md"}'),n={name:"en/guide/installation.md"};function l(o,e,r,d,c,h){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>See the full <a href="/clearance-docs/en/guide/introduction.html#requirements">requirements table</a> on the Introduction page - PHP ^8.3, Laravel ^11.0|^12.0|^13.0, spatie/laravel-permission ^6.0, livewire/livewire ^3.0|^4.0, livewire/flux ^2.14.</p><h2 id="install-the-package" tabindex="-1">Install the package <a class="header-anchor" href="#install-the-package" aria-label="Permalink to &quot;Install the package&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rivalex/clearance</span></span></code></pre></div><h2 id="run-the-installer" tabindex="-1">Run the installer <a class="header-anchor" href="#run-the-installer" aria-label="Permalink to &quot;Run the installer&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Always run clearance:install, never a plain migrate</p><p>Clearance&#39;s own migrations depend on Spatie&#39;s <code>roles</code>/<code>permissions</code> tables existing first; the installer publishes and runs Spatie&#39;s migrations before its own. If you run <code>php artisan migrate</code> directly on a fresh setup and Spatie isn&#39;t set up yet, you&#39;ll get an actionable error message telling you to run the installer instead.</p></div><h3 id="optional-flags" tabindex="-1">Optional flags <a class="header-anchor" href="#optional-flags" aria-label="Permalink to &quot;Optional flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--user=ID</code></td><td>Assign the <code>super_admin</code> role to a user after install</td></tr><tr><td><code>--role=NAME</code></td><td>Assign <code>clearance-access</code> to a role (created if absent)</td></tr><tr><td><code>--super-admin-role=NAME</code></td><td>Promote an existing role to <code>super_admin</code> (skips interactive prompt)</td></tr><tr><td><code>--force</code></td><td>Re-run even if already installed</td></tr></tbody></table><h3 id="what-the-installer-does" tabindex="-1">What the installer does <a class="header-anchor" href="#what-the-installer-does" aria-label="Permalink to &quot;What the installer does&quot;">​</a></h3><ol><li>Publishes <code>config/clearance.php</code>.</li><li>Publishes Clearance&#39;s migrations.</li><li>Detects Spatie Permission tables - if the <code>roles</code> table is absent, publishes and runs Spatie&#39;s migrations automatically first.</li><li>Runs all pending migrations.</li><li>Creates <code>clearance-access</code> and all 5 fine-grained capability permissions: <code>clearance-permissions-write</code>, <code>clearance-roles-write</code>, <code>clearance-guards-write</code>, <code>clearance-settings-write</code>, <code>clearance-users-write</code>.</li><li>Creates the <code>super_admin</code> role with all <code>clearance-*</code> permissions assigned (additive - never removes existing permissions on re-run).</li><li>Writes <code>storage/.clearance-installed</code> as an idempotency marker.</li></ol><div class="tip custom-block"><p class="custom-block-title">Migrating from an existing Spatie install?</p><p>Use <code>php artisan clearance:backfill</code> instead of starting from scratch, and read the <a href="/clearance-docs/en/guide/migration.html">Migration guide</a> first - it covers <code>super_admin</code> collision, custom model subclasses, and guard import.</p></div><h2 id="add-hasclearance-to-your-user-model" tabindex="-1">Add HasClearance to your User model <a class="header-anchor" href="#add-hasclearance-to-your-user-model" aria-label="Permalink to &quot;Add HasClearance to your User model&quot;">​</a></h2><p>To use contextual authorization methods (<code>$user-&gt;canIn()</code>, <code>$user-&gt;hasRoleIn()</code>), add the <code>HasClearance</code> trait to <code>App\\Models\\User</code>. It already includes Spatie&#39;s <code>HasRoles</code> - one line replaces both:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Traits\\HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> extends</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Authenticatable</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// includes HasRoles + all contextual authorization methods</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Already using <code>use HasRoles</code>?</p><p>Replace it with <code>use HasClearance</code>, or keep both - PHP deduplicates trait composition automatically, no conflicts.</p></div><p>Without this trait, <code>$user-&gt;canIn()</code> and related methods are unavailable, but the Blade directives (<code>@canin</code>, <code>@hasrolein</code>) and <code>ContextService</code> keep working regardless - they don&#39;t depend on the trait. See <a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a> for details.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Continue to the <a href="/clearance-docs/en/guide/quick-start.html">Quick Start</a> to mount the panel and start managing permissions.</p>`,20)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
